('e364f8977afc', 'Berita dan Pembaruan Skuad Piala Dunia 2026', 'Artikel ini menyediakan rangkuman berita dan pembaruan terkini mengenai Piala Dunia 2026 yang akan datang. Pembaca dapat menemukan informasi tentang pengumuman skuad tim, pemain kunci, serta detail mengenai stadion dan jadwal pertandingan.', '', 'nutrisi', 'BBC Sport', '[]', 'https://www.bbc.com/sport/football/world-cup', '2026-05-25 18:24:25'),
('e37f1a38182e', 'Latihan Pilates untuk Kekuatan Inti dan Stabilitas Bahu', 'Konten ini memperkenalkan latihan Pilates sederhana yang efektif. Latihan ini dirancang untuk membangun kekuatan inti yang dalam dan meningkatkan stabilitas bahu. Mengintegrasikan gerakan ini dapat membantu postur dan mengurangi risiko cedera.', 'https://cdn.mos.cms.futurecdn.net/XFAW8EcDfecmBstbbZWpNE-2560-80.jpg', 'umum', 'gnews.io', '[]', 'https://www.tomsguide.com/wellness/workouts/forget-sit-ups-and-crunches-i-use-this-simple-pilates-exercise-to-build-deep-core-strength-and-shoulder-stability', '2026-06-07 18:01:15'),
('e47758066299', 'Pembelaan Iga Swiatek untuk Prioritas Kebugaran Pemain Tenis', 'Iga Swiatek mengkritik direktur Dubai Championships, Salah Tahlak, karena menyarankan sanksi lebih ketat bagi pemain yang mundur dari turnamen. Ia membela hak pemain untuk memprioritaskan kebugaran dan mengatur jadwal mereka. Hal ini penting untuk menjaga performa dan kesehatan atlet dalam jangka panjang.', 'https://akm-img-a-in.tosshub.com/indiatoday/images/story/202605/iga-swiatek-234254712-16x9_0.jpg?VersionId=8UV0YuQVgujLgssjU1xdbPyrRAh3r_2J', 'umum', 'gnews.io', '[]', 'https://www.indiatoday.in/sports/tennis/story/iga-swiatek-dubai-championships-withdrawal-row-french-open-2915877-2026-05-23', '2026-05-23 17:54:54'),
('e497a4817db7', 'Manfaat Olahraga untuk Fokus dan Mencegah Kelelahan', 'Melakukan olahraga yang memberi energi dapat membantu Anda meningkatkan fokus. Dengan mengatur kecepatan diri, Anda bisa mencegah kelelahan. Ini menunjukkan bagaimana aktivitas fisik dapat mendukung kesejahteraan mental dan fisik.', 'https://static.toiimg.com/thumb/msid-131351176,width-1280,height-720,resizemode-6,overlay-toi_sw,pt-32,y_pad-600/photo.jpg', 'umum', 'gnews.io', '[\"Lakukan olahraga yang memberi energi untuk meningkatkan fokus.\", \"Atur kecepatan latihan Anda untuk mencegah kelelahan.\"]', 'https://timesofindia.indiatimes.com/astrology/numerology-tarot/numerology-horoscope-today-may-28-2026-what-your-names-first-letter-reveals-today/articleshow/131351201.cms', '2026-05-28 19:35:49'),
('e51ed6a61b48', 'Sesi Latihan Intensif Vaani Kapoor', 'Aktris Vaani Kapoor membagikan cuplikan sesi latihannya yang intens di media sosial. Ia menunjukkan bagaimana \'penderitaan memiliki manfaatnya\' dalam mencapai kebugaran.', 'https://d3pc1xvrcw35tl.cloudfront.net/ln/feedImages/1200x900/202606033812099_202606.jpeg', 'umum', 'gnews.io', '[]', 'https://www.lokmattimes.com/entertainment/vaani-kapoor-shows-how-suffering-has-its-benefits/', '2026-06-03 20:16:45'),
('e5d361e81897', 'Akasa Air Hadirkan Menu Sehat Spesial Hari Yoga', 'Sebuah maskapai penerbangan meluncurkan menu makanan khusus Hari Yoga, terinspirasi dari nutrisi seimbang. Menu ini dirancang untuk pelancong dan penggemar kebugaran yang mencari pilihan sehat saat bepergian.', 'https://media.assettype.com/freepressjournal/2026-06-19/as4yktkv/Rutunjay-2026-06-19T101000.260.png', 'umum', 'gnews.io', '[]', 'https://www.freepressjournal.in/lifestyle/staying-healthy-at-35000-feet-check-out-this-airlines-special-menu-on-occasion-of-international-yoga-day-2026', '2026-06-19 18:32:33'),
('e6c0f41d0881', '8 Bahaya Olahraga Berlebihan yang Perlu Diketahui', '', 'https://cdn.hellosehat.com/wp-content/uploads/2017/09/shutterstock_300224132-1000x400.jpg?wm=1', 'umum', 'hellosehat.com', '[]', 'https://hellosehat.com/kebugaran/olahraga-lainnya/bahaya-olahraga-berlebihan/', '2026-05-12 12:43:37');
INSERT INTO `education_articles` (`id`, `judul`, `ringkasan`, `gambar`, `kategori`, `sumber`, `tips`, `link_direct`, `updated_at`) VALUES
('e78fd0fe58a4', 'Manfaat Alpukat dan Alternatif Sehatnya', 'Alpukat toast sedang populer, namun apa saja manfaatnya? Artikel ini menjelaskan mengapa buah alpukat sehat dan memberikan saran alternatif untuk nutrisi optimal.', 'https://www.hindustantimes.com/ht-img/img/2026/06/19/550x309/avocado_1781847777331_1781847777447_d1f10978-f545-436a-9668-01931e2a6e45.jpeg', 'umum', 'gnews.io', '[]', 'https://www.hindustantimes.com/lifestyle/health/avocados-are-healthy-but-are-they-essential-tamannaah-bhatias-fitness-coach-explains-and-shares-budget-friendly-swaps-101781847137938.html', '2026-06-19 18:32:33'),
('eb2928d0c8ec', 'Perayaan Hari Jadi Asosiasi Bola Voli Jammu dan Kashmir', '', NULL, 'umum', 'newsdata.io', '[]', 'https://statetimes.in/vajk-celebrates-13th-foundation-day-of-art-of-giving-with-share-to-shine-message/', '2026-05-18 07:00:07'),
('ecd7e8aa4ef6', 'Tips Diet Bersih dan Rutinitas Olahraga Aktris', 'Aktris Dipika Kakar membahas tentang menjaga kesehatan melalui diet bersih dan rutinitas olahraga. Informasi ini berguna untuk memahami bagaimana selebriti menjaga kebugaran tubuh mereka. Artikel ini dapat memberikan inspirasi bagi pembaca untuk mulai menjalani gaya hidup sehat.', 'https://static.toiimg.com/thumb/msid-131161082,width-1280,height-720,imgsize-28964,resizemode-6,overlay-toi_sw,pt-32,y_pad-600/photo.jpg', 'nutrisi', 'gnews.io', '[]', 'https://timesofindia.indiatimes.com/tv/news/hindi/from-giving-a-tour-of-her-mothers-house-to-answering-fan-questions-about-her-health-clean-diet-and-workout-routine-dipika-kakar-gets-candid/photostory/131160810.cms', '2026-05-18 07:25:34'),
('ed41b56cf65f', 'Pre-SIR exercise in T: Alarm raised over functioning of BLOs', '', 'https://static.toiimg.com/thumb/msid-131157842,width-1280,height-720,resizemode-6,overlay-toi_sw,pt-32,y_pad-600/photo.jpg', 'umum', 'gnews.io', '[]', 'https://timesofindia.indiatimes.com/city/hyderabad/pre-sir-exercise-in-t-alarm-raised-over-functioning-of-blos/articleshow/131157843.cms', '2026-05-18 04:29:23'),
('ee7471135af8', '8 Ciri-Ciri Lemak Tubuh Anda Terbakar Saat Olahraga', '', 'https://cdn.hellosehat.com/wp-content/uploads/2019/09/lemak-terbuang-1000x400.jpg?wm=1', 'umum', 'hellosehat.com', '[]', 'https://hellosehat.com/kebugaran/olahraga-lainnya/ciri-lemak-terbakar-olahraga/', '2026-05-12 12:43:37'),
('ef5f2b063a96', 'Ekspansi Ekosistem Aplikasi Kesehatan & Kebugaran Huawei untuk HUAWEI WATCH FIT 5 Series', 'Huawei telah memperluas ekosistem aplikasi kesehatan dan kebugarannya pada seri terbaru HUAWEI WATCH FIT 5. Ekspansi ini menunjukkan komitmen perusahaan dalam memperkuat teknologi kebugaran. Pengguna dapat menikmati beragam fitur kesehatan melalui perangkat baru ini.', 'https://mmx.prnewswire.com/media/MS1868478/PR-Huawei-Watch-Fit-5-Health-Apps-ID-8ae0dcef6c7a.jpg?id=OA2723565&p=facebook', 'umum', 'gnews.io', '[]', 'https://www.prnewswire.co.uk/news-releases/huawei-expands-health-and-fitness-ecosystem-on-huawei-watch-fit-5-series-deepening-commitment-to-womens-wellbeing-302803549.html', '2026-06-18 19:18:39'),
('f07e8c7cf87d', 'Manfaat Peregangan Sebelum dan Sesudah Olahraga', 'Spesialis ortopedi menjelaskan dasar ilmiah di balik peregangan sebelum dan sesudah berolahraga. Ini mencakup perannya dalam pencegahan cedera dan pemulihan otot.', 'https://bsmedia.business-standard.com/_media/bs/img/article/2026-06/11/thumb/fitandfill/1200X628/1781173522-0889.jpg', 'umum', 'gnews.io', '[]', 'https://www.business-standard.com/health/fact-check-friday-should-you-stretch-before-or-after-a-workout-126061100717_1.html', '2026-06-12 19:00:04'),
('f0b8eec4fee9', 'Fungsi Sleep Tracking untuk Pelari: Lari Kencang Tanpa Lelah', '', 'https://cdn.hellosehat.com/wp-content/uploads/2025/10/c95be8f1-sleep-tracking-untuk-pelari-1000x400.jpg?wm=1', 'umum', 'hellosehat.com', '[]', 'https://hellosehat.com/kebugaran/kardio/sleep-tracking-untuk-pelari/', '2026-05-12 12:43:37'),
('f0c364c4de08', 'Mindy Kaling: Perjalanan Penurunan Berat Badan dan Rutinitas Kebugaran', 'Mindy Kaling berbagi kisah transformasinya dalam penurunan berat badan yang signifikan, termotivasi oleh perjalanan menjadi ibu dan masalah kesehatan. Artikel ini membahas wawasannya tentang tetap sehat, rutinitas kebugaran, dan menghadapi sorotan publik.', 'https://static.toiimg.com/thumb/msid-131219830,width-1280,height-720,resizemode-6,overlay-toi_sw,pt-32,y_pad-600/photo.jpg', 'umum', 'gnews.io', '[]', 'https://timesofindia.indiatimes.com/etimes/wellness/mindy-kaling-reveals-how-motherhood-inspired-her-weight-loss-journey/articleshow/131219493.cms', '2026-05-20 19:15:54'),
('f2e4f0362796', 'Kurangnya Akses Latihan Fisik di Udara Terbuka untuk Narapidana', 'Kekurangan staf dan perubahan kebijakan mengakibatkan narapidana dalam tahanan perlindungan dikurung di sel sepanjang hari. Kondisi ini membuat mereka tidak memiliki akses untuk berolahraga di udara terbuka, yang penting untuk kebugaran.', 'https://images.perthnow.com.au/publication/C-22440331/c25738ae97a11a54231c785b876bc96e8bc5d84f-16x9-x0y0w1280h720.jpg?imwidth=1200', 'umum', 'gnews.io', '[]', 'https://www.perthnow.com.au/news/politics/prisons-slammed-for-unlawful-and-oppressive-isolation-c-22440331', '2026-06-16 20:03:58'),
('f3108ccf9422', 'Perjalanan Kebugaran dan Kebiasaan Gaya Hidup Sehat', 'Seorang desainer dan ibu baru berbagi pengalaman tentang perjalanan kebugaran dan perubahan tubuhnya. Ia menyoroti kebiasaan gaya hidup kecil yang membantunya merasa lebih sehat selama bertahun-tahun. Artikel ini menawarkan wawasan tentang bagaimana adaptasi gaya hidup dapat mendukung kesehatan jangka panjang.', 'https://c.ndtvimg.com/2026-05/dmd2gr9o_masaba-gupta_625x300_22_May_26.png?im=FaceCrop,algorithm=dnn,width=1600,height=900', 'umum', 'gnews.io', '[]', 'https://www.ndtv.com/lifestyle/6-years-15-kg-and-1-baby-later-masaba-gupta-says-she-doesnt-recognise-herself-11531521', '2026-05-22 18:30:46'),
('f3191deebaa9', 'Cedera Pemain Sepak Bola: Absen Akibat Nyeri Setelah Latihan', 'Konten ini melaporkan seorang pemain depan bintang harus absen kembali dari pertandingan. Hal ini terjadi setelah ia merasakan nyeri parah pasca sesi latihan. Berita ini menyoroti pentingnya penanganan cedera dalam olahraga profesional.', 'https://images.7news.com.au/publication/C-22445574/26f9d6e8e6403ae7543f2d06d9a000edb39dc14a-16x9-x0y2w1280h720.jpg?imwidth=1200', 'umum', 'gnews.io', '[]', 'https://7news.com.au/sport/afl/fitness-worries-continue-for-in-form-hawthorn-veteran-jack-gunston-c-22445574', '2026-06-17 19:20:36'),
('f525a3513942', 'Manish Pandey Leads Kolkata Knight Riders to Victory, Praised for Fitness and Experience', 'Manish Pandey\'s decisive 45 runs secured a four-wicket victory for Kolkata Knight Riders against Mumbai Indians, boosting their IPL playoff hopes. Assistant coach Shane Watson highlighted Pandey\'s invaluable experience and impressive fitness, noting his consistent form across every IPL season.', 'https://img.etimg.com/thumb/msid-131241326,width-1200,height-630,imgsize-70066,overlay-economictimes/articleshow.jpg', 'umum', 'gnews.io', '[]', 'https://economictimes.indiatimes.com/news/sports/ipl-2026-cricket-veteran-manish-pandey-adding-value-to-kolkatas-ipl-campaign-says-watson/articleshow/131241255.cms', '2026-05-21 18:54:11'),
('f5d220ad528e', 'Isha Koppikar\'s Fitness Journey: Discipline Over Motivation', 'Isha Koppikar, 49, shared her fitness journey, emphasizing discipline over motivation and consistent effort for change. A fitness expert added that taking action even on low-motivation days builds momentum and strengthens habits. Prioritizing functional and psychological outcomes over aesthetics makes a routine sustainable.', 'https://images.indianexpress.com/2026/04/isha-koppikar_1600_insta.jpg', 'umum', 'gnews.io', '[\"Focus on discipline over motivation for your fitness journey.\", \"Understand that consistent effort, not instant results, drives true change.\", \"Take action even on low-motivation days to build momentum and strengthen habits.\", \"Prioritize functional and psychological outcomes like energy and strength over just aesthetics.\", \"Embrace that progress comes from repeated, imperfect effort and internal health markers.\"]', 'https://indianexpress.com/article/lifestyle/fitness/isha-koppikar-fitness-journey-discipline-expert-10625445/', '2026-06-03 20:16:45'),
('f633b161fffc', 'Ed Warner on Enhanced Games: Athletes and Sport Not the Main Story', 'Ed Warner discusses the inaugural Enhanced Games, suggesting that the athletes and the sport itself are not the primary focus. He elaborates on the underlying narratives overshadowing the traditional elements of competition.', 'https://www.cityam.com/wp-content/uploads/2026/05/GettyImages-1405170543-e1779280523135.jpg', 'umum', 'gnews.io', '[]', 'https://www.cityam.com/enhanced-games-isnt-sport-but-a-product-placement-exercise/', '2026-05-21 18:54:11'),
('f68fe72f7831', 'Cedera Hamstring Virat Kohli Mengancam Partisipasi di Seri ODI Afghanistan', 'Pemain kriket bintang, Virat Kohli, dilaporkan mengalami cedera hamstring serius yang mungkin membuatnya absen dari tiga pertandingan seri ODI melawan Afghanistan mulai 13 Juni. Cedera ini menjadi pukulan besar bagi tim India menjelang turnamen penting. Kondisi kebugaran Kohli akan sangat diawasi untuk pemulihan.', 'https://img.onmanorama.com/content/dam/mm/en/sports/cricket/images/2025/2/6/virat-kohli-afp.jpg', 'umum', 'gnews.io', '[]', 'https://www.onmanorama.com/sports/cricket/2026/06/04/virat-kohli-likely-to-miss-odi-series-against-afghanistan-with-injury.html', '2026-06-04 19:14:54'),
('f745f89025b0', 'Rahasia Kebugaran Trisha Krishnan: Sesi Pilates untuk Kekuatan Inti dan Postur', 'Para ahli mengupas sesi Pilates intens Trisha Krishnan yang berfokus pada ketepatan gerakan. Mesin Reformer menyediakan resistansi kuat yang membangun kekuatan inti dalam. Latihan ini juga sangat efektif untuk mengoreksi postur tubuh.', 'https://images.indianexpress.com/2026/05/Trisha-Krishnan-Pilates.jpg', 'postur', 'gnews.io', '[\"Gunakan mesin Reformer Pilates untuk membangun kekuatan inti yang mendalam.\", \"Fokus pada presisi dalam gerakan Pilates untuk mengoreksi postur tubuh Anda secara efektif.\"]', 'https://indianexpress.com/article/lifestyle/fitness/trisha-krishnan-pilates-reformer-5-moves-beginners-10685791/', '2026-05-31 17:56:20'),
('f876957d4a71', 'Peningkatan Pelacakan Kebugaran di Google Health 5.01', 'Google Health versi 5.01 meluncurkan 16 perbaikan dan peningkatan besar. Ini termasuk skor tidur yang lebih andal, pencatatan makanan khusus, pelacakan kebugaran yang ditingkatkan, dan migrasi akun Fitbit yang lebih lancar.', 'https://img.republicworld.com/all_images/2026/06/google-health-501-rolls-out-reliable-sleep-scores-custom-food-logging-lead-16-big-fixes-1780638310353-1280x720.webp', 'umum', 'gnews.io', '[]', 'https://www.republicworld.com/tech/google-health-501-rolls-out-reliable-sleep-scores-custom-food-logging-lead-16-big-fixes-2026-06-05-127017', '2026-06-05 18:56:40'),
('f92e5e4d305a', '8 Teknik Lari yang Benar, Cocok Diterapkan oleh Pemula', '', 'https://cdn.hellosehat.com/wp-content/uploads/2026/02/29c58ceb-shutterstock_2431767195-1771483193-1000x400.jpg?wm=1', 'umum', 'hellosehat.com', '[]', 'https://hellosehat.com/kebugaran/tips-olahraga/8-teknik-lari-yang-benar-cocok-diterapkan-oleh-pemula/', '2026-05-12 12:43:37'),
('fa8f0708c69a', 'Strategi Nutrisi Pasca Bersepeda untuk Performa Lebih Baik', 'Penelitian menunjukkan bahwa nutrisi dan hidrasi setelah bersepeda sama pentingnya dengan asupan selama perjalanan. Apa yang Anda makan dan minum pasca bersepeda memiliki peran krusial. Ini dapat memengaruhi kecepatan dan performa Anda.', 'https://www.bicycling.co.za/wp-content/uploads/2026/06/post-ride-nutrition-getty.jpg', 'umum', 'newsdata.io', '[]', 'https://www.bicycling.co.za/nutrition/the-post-ride-nutrition-strategy-that-makes-you-faster/', '2026-06-17 19:20:36'),
('fa9fb63535fb', 'Kelebihan dan Kekurangan Gym Digital Dibandingkan Latihan Rumahan Tradisional', 'Artikel ini membahas tentang tren gym digital yang semakin populer. Dibahas fitur, manfaat, dan kekurangan gym digital jika dibandingkan dengan metode latihan di rumah secara tradisional. Ini memberikan perbandingan komprehensif untuk membantu memilih opsi kebugaran terbaik.', 'https://cassette.sphdigital.com.sg/image/straitstimes/d4275b27d45e2dbfcc25fc3596ca9076e676cb54e629ecd77bc20a542a36a946', 'umum', 'gnews.io', '[]', 'https://www.straitstimes.com/life/home-design/no-more-dumbbells-or-weight-plates-could-a-digital-home-gym-replace-your-gym-membership', '2026-05-22 18:30:46'),
('fb7acec7d706', 'Walking Strategies for Overall Health', '', 'https://www.verywellfit.com/thmb/B6I_sbLCfMgi1ztkJMnw1skc0z4=/1500x0/filters:no_upscale():max_bytes(150000):strip_icc()/Illo_Walking-ba697c31eb9a40e5bd1f0d13f40cba93.jpg', 'nutrisi', 'Verywell Fit', '[]', 'https://www.verywellfit.com/walking-overview-4581844', '2026-05-12 12:43:37'),
('fb8aaf98959d', 'Pembukaan Fasilitas Pelatihan Premium UFC GYM di Jammu', 'UFC GYM® telah membuka fasilitas pelatihan premium terbarunya di Jammu, India. Dengan luas 15.000 kaki persegi, fasilitas ini menjadi destinasi utama untuk kebugaran terinspirasi MMA dan kesehatan holistik di wilayah tersebut.', 'https://www.tribuneindia.com/sortd-service/imaginary/v22-01/jpg/large/high?url=dGhldHJpYnVuZS1zb3J0ZC1wcm8tcHJvZC1zb3J0ZC9tZWRpYWY1NDM1ZDQwLTUyNzUtMTFmMS05NWQzLWFiMTg3NjE5Y2M0NS5qcGc=', 'umum', 'gnews.io', '[]', 'https://www.tribuneindia.com/news/business/ufc-gym-india-announces-the-grand-opening-of-its-newest-premium-fitness-club-in-jammu/', '2026-05-18 18:30:47'),
('fda2e2126dc4', 'Festival Olahraga Komunitas', 'Sebuah festival komunitas telah diselenggarakan, menampilkan berbagai kegiatan olahraga yang menarik. Para peserta dapat mencoba pickleball, frisbee golf, dan tyre flips. Acara ini mendorong partisipasi aktif dalam kebugaran.', 'https://cassette.sphdigital.com.sg/image/straitstimes/de27e51f0a43b1c12fcc035011f1c56fb63a58f97950b8315af07433e74d6761', 'umum', 'gnews.io', '[]', 'https://www.straitstimes.com/singapore/community/over-6000-people-from-north-west-district-join-fitness-festival-to-keep-active', '2026-06-07 18:01:15'),
('fe6e55f03408', 'Colorado\'s AI Anti-Discrimination Law Is Dead Before It Ever Took Effect: Replaced With Notice-Only Framework', '', 'https://d.techtimes.com/en/full/464972/colorado-governor-jared-polis-speaks-during-community-gathering.jpg', 'umum', 'newsdata.io', '[]', 'https://www.techtimes.com/articles/316756/20260517/colorados-ai-anti-discrimination-law-dead-before-it-ever-took-effect-replaced-notice-only.htm', '2026-05-18 04:29:23');

